func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    type candidate struct {
        idx       int
        deltaCost float64
        ok        bool
    }
    for shipIdx := range oris {
        bestCand := candidate{-1, 0, false}
        shipID := total_ship + shipIdx
        // evaluate all current non-empty assigns plus one potential new empty assign
        limit := dispatch.AssignsLen
        for i := 0; i <= limit; i++ {
            if i == limit {
                // try a fresh empty assign if within bounds
                if i >= MAXASSIGNS {
                    continue
                }
            }
            assign := &dispatch.Assigns[i]
            backupCost := assign.Cost
            success := assign.AddShip(shipID, oris[shipIdx], dess[shipIdx])
            if !success {
                if i < dispatch.AssignsLen {
                    assign.Cost = backupCost
                }
                continue
            }
            oldCost := backupCost
            assign.GenRoute()
            newCost := assign.Cost
            if newCost < 0 {
                assign.RemoveShip(shipID)
                assign.GenRoute()
                assign.Cost = backupCost
                continue
            }
            delta := newCost - oldCost
            if !bestCand.ok || delta < bestCand.deltaCost {
                bestCand.idx = i
                bestCand.deltaCost = delta
                bestCand.ok = true
            }
            // rollback trial
            assign.RemoveShip(shipID)
            assign.GenRoute()
            assign.Cost = backupCost
        }
        if bestCand.ok {
            chosen := &dispatch.Assigns[bestCand.idx]
            chosen.AddShip(shipID, oris[shipIdx], dess[shipIdx])
            chosen.GenRoute()
            if bestCand.idx >= dispatch.AssignsLen {
                dispatch.AssignsLen++
            }
        } else {
            // safe seed: create new assign if possible
            if dispatch.AssignsLen < MAXASSIGNS {
                newAssign := &dispatch.Assigns[dispatch.AssignsLen]
                newAssign.AddShip(shipID, oris[shipIdx], dess[shipIdx])
                newAssign.GenRoute()
                dispatch.AssignsLen++
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

